/**
 * ==========================================================
 * TOPIC: REACT STATE & RENDERING (THE SNAPSHOT THEORY)
 * ==========================================================
 * হাসান, রিয়্যাক্টে স্টেট মানে হলো কম্পোনেন্টের "স্মৃতি" (Memory)।
 * সাধারণ ভেরিয়েবল আর স্টেটের মধ্যে মেইন পার্থক্য হলো:
 * স্টেট পরিবর্তন হলে রিয়্যাক্ট নিজে থেকে UI আপডেট (Re-render) করে।
 */

import { useState } from "react";

/**
 * ১. সাধারণ ভেরিয়েবল কেন কাজ করে না?
 * --------------------------------
 * তুমি যদি 'let index = 0' ব্যবহার করো, তবে:
 * ক. রেন্ডারের মাঝখানে ডাটা হারিয়ে যায় (প্রতিবার ফাংশন নতুন করে রান হয়)।
 * খ. ডাটা চেঞ্জ হলেও রিয়্যাক্ট বুঝতে পারে না যে তাকে UI বদলাতে হবে।
 * * সমাধান: useState Hook। এটি রিয়্যাক্টকে বলে—"এই ডাটা মনে রাখো এবং এটা বদলালে UI আপডেট করো।"
 */

export default function Gallery() {
  // [বর্তমান ভ্যালু, ভ্যালু বদলানোর ফাংশন] = useState(শুরুতে যা থাকবে)
  const [index, setIndex] = useState(0);

  function handleClick() {
    setIndex(index + 1); // এটি রিয়্যাক্টকে একটা Re-render কিউ (Queue) তে পাঠায়
  }

  return <button onClick={handleClick}>Next</button>;
}

/**
 * ২. রেন্ডারিং প্রসেস (The Waiter Analogy)
 * --------------------------------------
 * রিয়্যাক্টের রেন্ডারিং ৩টি ধাপে ঘটে:
 * ১. Trigger (অর্ডার দেওয়া): স্টেটে হাত দিলেই রিয়্যাক্টের কাছে রেন্ডারের রিকোয়েস্ট যায়।
 * ২. Render (রান্না করা): রিয়্যাক্ট তোমার কম্পোনেন্ট ফাংশনটি কল করে দেখে কী কী বদলাবে।
 * ৩. Commit (টেবিলে খাবার দেওয়া): রিয়্যাক্ট শুধু যতটুকু বদলেছে ঠিক ততটুকুই আসল DOM-এ আপডেট করে।
 */

/**
 * ৩. স্টেট একটি "Snapshot" (খুবই জরুরি কনসেপ্ট 🧠)
 * ---------------------------------------------
 * হাসান, রেন্ডারিং মানে হলো ওই মুহূর্তের UI-এর একটা ছবি তোলা।
 * যখন রিয়্যাক্ট কোনো কম্পোনেন্ট রেন্ডার করে, সে ওই সময়ের স্টেট ভ্যালুকে 'ফ্রিজ' করে দেয়।
 */

export function Counter() {
  const [number, setNumber] = useState(0);

  return (
    <>
      <h1>{number}</h1>
      <button
        onClick={() => {
          setNumber(number + 5);
          alert(number);
          /* হাসান, এখানে ম্যাজিকটা দেখো:
          তুমি setNumber(number + 5) করেছো ঠিকই, কিন্তু এলার্ট বক্সে তুমি '0' ই দেখতে পাবে।
          কেন? কারণ এই নির্দিষ্ট রেন্ডারে 'number' এর মান ০ হিসেবে ফিক্সড বা স্ন্যাপশট হয়ে আছে।
          নতুন মান (৫) তুমি কেবল পরবর্তী রেন্ডারে পাবে।
        */
        }}
      >
        +5
      </button>
    </>
  );
}

/**
 * ৪. কেন +১ করে ৩ বার লিখলে ৩ বাড়ে না?
 * -----------------------------------
 * <button onClick={() => {
 * setNumber(number + 1);
 * setNumber(number + 1);
 * setNumber(number + 1);
 * }}>+3</button>
 * * এখানে আউটপুট ১-ই হবে। কারণ প্রতিবার তুমি বলছেন 'setNumber(0 + 1)'।
 * রিয়্যাক্ট ৩ বার একই স্ন্যাপশট ভ্যালু (০) ব্যবহার করে আপডেট করছে।
 *
 *  * কেন ফাংশন (n => n + 1) দিলে ডাটা হারায় না?
 * ---------------------------------------
 */

// ১. সরাসরি ভ্যালু (No Memory of Previous Step)
setNumber(number + 1); // রিয়্যাক্ট শুধু 'মান' পায়। আগের বার কী সেট হয়েছিল সে জানে না।

// ২. আপডেটার ফাংশন (Chain of Memory)
setNumber((n) => n + 1);
/** * এখানে 'n' হলো "Pending State"। 
 * রিয়্যাক্ট গ্যারান্টি দেয় যে, এই 'n' সবসময় আগের আপডেটার ফাংশনের 
 * লেটেস্ট রেজাল্টটাকেই রিসিভ করবে। 
 * একে বলা হয় 'Functional Update' বা 'Updater Pattern'।

 * 
 */

/**
 * ৫. হুকস (Hooks) ব্যবহারের নিয়ম
 * ---------------------------
 * - সবসময় কম্পোনেন্টের শুরুতে (Top Level) কল করতে হবে।
 * - লুপ (loop), কন্ডিশন (if) বা নেস্টেড ফাংশনের ভেতর হুক কল করা নিষেধ।
 * - রিয়্যাক্ট ইন্টারনালি একটি অ্যারের (Array) মাধ্যমে মনে রাখে কোন হুক আগে কল হয়েছে।
 * তাই কল করার সিরিয়াল ঠিক রাখা ম্যান্ডেটরি।
 */

/**
 * ৬. স্টেটের গোপনীয়তা (State is Isolated & Private)
 * ----------------------------------------------
 * হাসান, তুমি যদি স্ক্রিনে <Gallery /> দুইবার লেখো, তবে দুইটা গ্যালারি
 * আলাদা আলাদাভাবে কাজ করবে। একজনের ইনডেক্স বাড়লে অন্যজনের কোনো পরিবর্তন হবে না।
 * রিয়্যাক্ট প্রতিটি কম্পোনেন্টের জন্য আলাদা 'Memory Shelf' রাখে।
 */

/**
 * ==========================================================
 * হাসান'স মাস্টার সামারি:
 * ==========================================================
 * ১. State = Component's memory (যা রেন্ডারের পরেও টিকে থাকে)।
 * ২. Setter function (setIndex) কল করলেই কেবল রেন্ডার ট্রিগার হয়।
 * ৩. Render = ফাংশনটি আবার কল হওয়া।
 * ৪. Snapshot = ফাংশন কল হওয়ার সময় স্টেটের মান ফিক্সড হয়ে যায়।
 * ৫. Commit = রিয়্যাক্ট ডোম-এ শুধু পার্থক্যটুকু (Diff) পাঠায়।
 */

console.log("Hasan, State and Rendering Master Note is updated!");

